int vertices = 5;
vector<vector<int>> adj(vertices); // adj[i] holds a list of i's DIRECT neighbors

// Add an undirected edge between vertex 0 and vertex 1:
adj[0].push_back(1);
adj[1].push_back(0); // undirected — record BOTH directions

#include <iostream>
#include <vector>

using namespace std;

int main()
{
    int vertices = 4;
    vector<vector<int>> adj(vertices);

    // Undirected edges: 0-1, 0-2, 1-3
    adj[0].push_back(1); adj[1].push_back(0);
    adj[0].push_back(2); adj[2].push_back(0);
    adj[1].push_back(3); adj[3].push_back(1);

    for (int v = 0; v < vertices; v++)
    {
        cout << v << ": ";
        for (int neighbor : adj[v])
        {
            cout << neighbor << " ";
        }
        cout << endl;
    }

    return 0;
}

